fn solve(grid: Vec<Vec<i64>>, x: i64, y: i64, k: i64) -> Vec<Vec<i64>> {
    let mut matrix = grid;
    let k = k as usize;
    let x = x as usize;
    let y = y as usize;

    // Extract the submatrix
    let submatrix: Vec<Vec<i64>> = matrix[x..x + k].iter()
        .map(|row| row[y..y + k].to_vec())
        .collect();

    // Reverse the submatrix
    let reversed_submatrix: Vec<Vec<i64>> = submatrix.iter().rev().cloned().collect();

    // Replace the original submatrix with the reversed one
    for i in 0..k {
        for j in 0..k {
            matrix[x + i][y + j] = reversed_submatrix[i][j];
        }
    }

    matrix
}
